, reject as (
Select 
    c.WithdrawID,
    w.Comment,
    row_number() over (partition by w.WithdrawID order by w.ModificationDate asc) as rn
FROM 
    co c
JOIN 
    main.billing.bronze_etoro_history_withdrawaction w on w.WithdrawID = c.WithdrawID
WHERE 
    w.CashoutStatusID = 2 and w.ManagerID<>0 and w.Comment is not null and  w.Comment RLIKE '[A-Za-z0-9]'
)

Select distinct
    co.*,
    r.Comment as RejectReason
FROM 
    co
LEFT JOIN 
    reject r on r.WithdrawID = co.WithdrawID and r.rn = 1